sql:
SELECT COUNT(user_id) AS user_count
FROM genre_preferences
WHERE genre_id = 2;

SELECT COUNT(user_id) AS number_of_users
FROM user_genres
WHERE rating = -3 AND genre_id = 2;

external_knowledge:
- A higher average rating indicates a more favored genre among users;
- The rating scale ranges from -3 to 3, where 3 is the highest possible rating;
- The query aims to find the genre with the highest aggregate user preference.

sql:
SELECT AVG(mr.rating) AS avg_movie_rating
FROM movie_ratings mr
JOIN genre_preferences gp ON mr.user_id = gp.user_id;

SELECT movie_id, AVG(rating) AS average_rating, COUNT(movie_rating_id) AS rating_count
FROM movie_ratings
GROUP BY movie_id;

SELECT AVG(rating) AS overall_average_rating
FROM movie_ratings
WHERE movie_id = 1;
